class Solution {
public:
    int findBestValue(vector<int>& arr, int target) {
        int left = 0, right = *max_element(arr.begin(), arr.end());
        int closestSum = INT_MAX, result = INT_MAX;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            int sum = getSum(arr, mid);
            if (abs(sum - target) < abs(closestSum - target) || 
                (abs(sum - target) == abs(closestSum - target) && mid < result)) {
                closestSum = sum;
                result = mid;
            }
            if (sum < target) left = mid + 1;
            else right = mid - 1;
        }
        return result;
    }

    int getSum(vector<int>& arr, int val) {
        int sum = 0;
        for (int num : arr) sum += min(num, val);
        return sum;
    }
};
